import{_ as s,o as a,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Qwen","description":"","frontmatter":{"summary":"Use Qwen OAuth (free tier) in OpenSoul","read_when":["You want to use Qwen with OpenSoul","You want free-tier OAuth access to Qwen Coder"],"title":"Qwen"},"headers":[],"relativePath":"providers/qwen.md","filePath":"providers/qwen.md","lastUpdated":1771906665000}'),t={name:"providers/qwen.md"};function l(o,e,d,r,h,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="qwen" tabindex="-1"><a class="header-anchor" href="#qwen">#</a> Qwen</h1><p>Qwen provides a free-tier OAuth flow for Qwen Coder and Qwen Vision models (2,000 requests/day, subject to Qwen rate limits).</p><h2 id="enable-the-plugin" tabindex="-1"><a class="header-anchor" href="#enable-the-plugin">#</a> Enable the plugin</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal-auth</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Restart the Gateway after enabling.</p><h2 id="authenticate" tabindex="-1"><a class="header-anchor" href="#authenticate">#</a> Authenticate</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This runs the Qwen device-code OAuth flow and writes a provider entry to your <code>models.json</code> (plus a <code>qwen</code> alias for quick switching).</p><h2 id="model-ids" tabindex="-1"><a class="header-anchor" href="#model-ids">#</a> Model IDs</h2><ul><li><code>qwen-portal/coder-model</code></li><li><code>qwen-portal/vision-model</code></li></ul><p>Switch models with:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen-portal/coder-model</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="reuse-qwen-code-cli-login" tabindex="-1"><a class="header-anchor" href="#reuse-qwen-code-cli-login">#</a> Reuse Qwen Code CLI login</h2><p>If you already logged in with the Qwen Code CLI, OpenSoul will sync credentials from <code>~/.qwen/oauth_creds.json</code> when it loads the auth store. You still need a <code>models.providers.qwen-portal</code> entry (use the login command above to create one).</p><h2 id="notes" tabindex="-1"><a class="header-anchor" href="#notes">#</a> Notes</h2><ul><li>Tokens auto-refresh; re-run the login command if refresh fails or access is revoked.</li><li>Default base URL: <code>https://portal.qwen.ai/v1</code> (override with <code>models.providers.qwen-portal.baseUrl</code> if Qwen provides a different endpoint).</li><li>See <a href="/docs/concepts/model-providers">Model providers</a> for provider-wide rules.</li></ul>',16)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
